const items = $input.all();
const results = [];
for (const item of items.slice(0, 30)) {
  const d = item.json;
  results.push({ json: { platform: 'reddit', content_type: 'social_post', title: d.title || '', body: (d.body || d.text || d.selftext || '').substring(0, 2000), url: d.url || '', author: d.author || '', score: d.score || d.upVotes || 0, created_at: d.createdAt || d.created || new Date().toISOString() } });
}
return results.length > 0 ? results : [{ json: { _empty: true, platform: 'reddit' } }];

const items = $input.all();
const results = [];
for (const place of items) {
  const d = place.json;
  const reviews = d.reviews || [];
  const placeUrl = d.url || d.placeUrl || '';
  for (const review of reviews.slice(0, 10)) {
    const author = review.name || review.reviewerName || 'anonymous';
    const dateStr = review.publishedAtDate || '';
    const safeAuthor = author.replace(/[^a-zA-Z0-9]/g, '-').substring(0, 40);
    const safeDate = dateStr.replace(/[^a-zA-Z0-9]/g, '-').substring(0, 20);
    const uniqueUrl = placeUrl ? `${placeUrl}#review-${safeAuthor}-${safeDate}` : '';
    results.push({ json: { platform: 'google_maps', content_type: 'review', title: d.title || d.name || '', body: (review.text || review.textTranslated || '').substring(0, 2000), url: uniqueUrl, author: author, score: review.stars || 0, created_at: review.publishedAtDate || new Date().toISOString() } });
  }
  if (reviews.length === 0) {
    results.push({ json: { platform: 'google_maps', content_type: 'listing', title: d.title || d.name || '', body: (d.description || d.categoryName || '').substring(0, 2000), url: placeUrl, author: '', score: d.totalScore || 0, created_at: new Date().toISOString() } });
  }
}
return results.length > 0 ? results : [{ json: { _empty: true, platform: 'google_maps' } }];

const items = $input.all();
const batchSize = 10;
const batches = [];
for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize);
  const contentList = batch.map((item, idx) => {
    const d = item.json;
    return `--- Item ${idx + 1} ---\nPlatform: ${d.platform}\nTitle: ${d.title}\nContent: ${(d.body || '').substring(0, 800)}\nURL: ${d.url || ''}`;
  }).join('\n\n');
  batches.push({ json: { batchIndex: Math.floor(i / batchSize), itemCount: batch.length, contentList: contentList } });
}
return batches.length > 0 ? batches : [{ json: { _skip: true } }];

const items = $input.all();
const results = [];
const industry = $('Set Search Parameters').first().json.industry;

function parseMonetary(val) {
  if (val == null) return null;
  if (typeof val === 'number') return val;
  const str = String(val);
  const match = str.match(/\$?([\d,]+\.?\d*)/);
  if (match) return parseFloat(match[1].replace(/,/g, ''));
  return null;
}

for (const item of items) {
  try {
    const aiResponse = item.json;
    let textContent = '';
    if (aiResponse.content && Array.isArray(aiResponse.content)) {
      textContent = aiResponse.content.map(c => c.text || '').join('');
    } else if (typeof aiResponse.text === 'string') {
      textContent = aiResponse.text;
    } else if (typeof aiResponse.message === 'object' && aiResponse.message?.content) {
      textContent = Array.isArray(aiResponse.message.content)
        ? aiResponse.message.content.map(c => c.text || '').join('')
        : String(aiResponse.message.content);
    }
    const jsonMatch = textContent.match(/\[[\s\S]*\]/);
    if (!jsonMatch) continue;
    const painPoints = JSON.parse(jsonMatch[0]);
    for (const pp of painPoints) {
      if (!pp.category || !pp.severity) continue;
      results.push({ json: { pain_point_category_name: pp.category, source_type: 'market_intelligence', source_id: pp.source_excerpt ? pp.source_excerpt.substring(0, 50) : 'social_scrape', source_excerpt: (pp.source_excerpt || '').substring(0, 500), confidence_score: pp.confidence_score ?? 0.4, monetary_indicator: parseMonetary(pp.monetary_indicator), monetary_context: (typeof pp.monetary_indicator === 'string' && pp.monetary_indicator) ? pp.monetary_indicator : null, industry: industry || null } });
    }
  } catch (err) { /* skip */ }
}
return results.length > 0 ? results : [{ json: { _skip: true } }];

const items = $input.all();
const results = [];
for (const item of items.slice(0, 30)) {
  const d = item.json;
  const body = String(d.content || d.text || d.commentary || '').substring(0, 2000);
  if (!body || body.length < 20) continue;
  const authorName = (d.author && typeof d.author === 'object') ? (d.author.name || '') : String(d.author || '');
  const postDate = (d.postedAt && typeof d.postedAt === 'object') ? (d.postedAt.date || '') : String(d.postedAt || '');
  results.push({
    json: {
      platform: 'linkedin',
      content_type: 'post',
      title: '',
      body: body,
      url: d.linkedinUrl || d.url || d.postUrl || '',
      author: authorName,
      score: (d.socialDetail && d.socialDetail.totalSocialActivityCounts) ? (d.socialDetail.totalSocialActivityCounts.numLikes || 0) : (d.numLikes || d.likeCount || 0),
      created_at: postDate || new Date().toISOString()
    }
  });
}
return results.length > 0 ? results : [{ json: { _empty: true, platform: 'linkedin' } }];

const urls = JSON.parse($json.g2ProductUrls);
const results = [];
for (const url of urls) {
  results.push({ json: { url: url, maxReviews: 10, lookbackDays: 90 } });
}
return results;

const items = $input.all();
const results = [];
for (const item of items.slice(0, 50)) {
  const d = item.json;
  const pros = d.pros || d.advantages || '';
  const cons = d.cons || d.disadvantages || '';
  const review = d.content || d.review_text || d.text || d.comment || d.review || '';
  const body = [pros ? `Pros: ${pros}` : '', cons ? `Cons: ${cons}` : '', review].filter(Boolean).join('\n').substring(0, 2000);
  if (!body || body.length < 20) continue;
  // Build unique URL: use the review's unique id from the actor, or fall back to product URL + author hash
  let reviewUrl = '';
  if (d.id) {
    const productUrl = d.product_url || d.review_url || d.url || '';
    const baseUrl = productUrl.split('?')[0];
    reviewUrl = baseUrl ? `${baseUrl}#${d.id}` : d.id;
  } else {
    const productUrl = d.product_url || d.review_url || d.url || '';
    const author = d.author || d.reviewer_name || d.reviewerName || 'anon';
    const date = d.date_posted || d.date || d.published_date || d.publishedDate || '';
    const safeAuthor = author.replace(/[^a-zA-Z0-9]/g, '-').substring(0, 40);
    const safeDate = date.replace(/[^a-zA-Z0-9]/g, '-').substring(0, 20);
    reviewUrl = productUrl ? `${productUrl.split('?')[0]}#review-${safeAuthor}-${safeDate}` : `g2-review-${safeAuthor}-${safeDate}`;
  }
  results.push({
    json: {
      platform: 'g2',
      content_type: 'review',
      title: d.title || d.product_name || d.productName || '',
      body: body,
      url: reviewUrl,
      author: d.author || d.reviewer_name || d.reviewerName || '',
      score: d.rating || d.star_rating || d.overall_rating || 0,
      created_at: d.date_posted || d.date || d.published_date || d.publishedDate || new Date().toISOString()
    }
  });
}
return results.length > 0 ? results : [{ json: { _empty: true, platform: 'g2' } }];

